function uuidv4(){return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g,c=>{const r=Math.random()*16|0;return(c==="x"?r:(r&0x3|0x8)).toString(16);})}
const input = $input.first().json || {};
const body = input.body || input;
// Determine content type from input or by week number
let ct = body.content_type || '';
if (!ct) {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 1);
  const week = Math.ceil(((now - start) / 86400000 + start.getDay() + 1) / 7);
  const types = ['upcoming_games', 'game_review', 'industry_news', 'monthly_games'];
  ct = types[(week - 1) % 4];
}
return [{ json: { content_type: ct, run_id: uuidv4() } }];

