  const result = { ...d, run_id: $('Parse Gate Approval').first().json.run_id };
  return [{ json: result }];
} catch(e) {
  const errMatch = stderr.match(/Error: (.+)/);
  throw new Error('Parse voiceover failed: ' + (errMatch ? errMatch[1] : e.message));
}

